def step1_validate_cart(cart_items: list[CartItem], user: User) -> dict:
    """
    Step 1: Validate cart items.
    Checks: non-empty cart, item availability, valid quantities, valid prices.
    Returns validated cart summary.
    """
    print(f"\n{'='*60}")
    print(f"STEP 1: Validating cart for user '{user.name}' ({user.tier.value})")
    print(f"{'='*60}")

    if not cart_items:
        raise CartValidationError("Cart is empty. Cannot proceed with checkout.")

    validated_items = []
    subtotal = 0.0
    errors = []

    for item in cart_items:
        item_errors = []

        if not item.in_stock:
            item_errors.append(f"'{item.name}' is out of stock")

        if item.quantity <= 0:
            item_errors.append(f"'{item.name}' has invalid quantity: {item.quantity}")
        elif item.quantity > item.max_quantity:
            item_errors.append(
                f"'{item.name}' quantity ({item.quantity}) exceeds maximum allowed ({item.max_quantity})"
            )

        if item.price < 0:
            item_errors.append(f"'{item.name}' has invalid price: ${item.price:.2f}")

        if item_errors:
            errors.extend(item_errors)
        else:
            item_total = item.price * item.quantity
            subtotal += item_total
            validated_items.append({
                "product_id": item.product_id,
                "name": item.name,
                "price": item.price,
                "quantity": item.quantity,
                "item_total": round(item_total, 2)
            })
            print(f"  ✓ {item.name} x{item.quantity} @ ${item.price:.2f} = ${item_total:.2f}")

    if errors:
        raise CartValidationError(
            "Cart validation failed:\n  - " + "\n  - ".join(errors)
        )

    subtotal = round(subtotal, 2)
    print(f"\n  Cart validated successfully!")
    print(f"  Subtotal: ${subtotal:.2f}")
    print(f"  Items count: {len(validated_items)}")

    return {
        "validated_items": validated_items,
        "subtotal": subtotal,
        "item_count": len(validated_items),
        "user": user
    }


def step2_apply_discount(
    cart_summary: dict,
    discount_code: Optional[str] = None
) -> dict:
    """
    Step 2: Apply discount code.
    Validates user permissions for the discount code and applies it.
    Returns updated cart summary with discount information.
    """
    print(f"\n{'='*60}")
    print(f"STEP 2: Applying discount code")
    print(f"{'='*60}")

    subtotal = cart_summary["subtotal"]
    user: User = cart_summary["user"]
    discount_amount = 0.0
    discount_info = None

    if discount_code is None or discount_code.strip() == "":
        print("  No discount code provided. Skipping discount step.")
        return {
            **cart_summary,
            "discount_amount": 0.0,
            "discount_code_used": None,
            "subtotal_after_discount": subtotal,
            "discount_info": None
        }

    code_upper = discount_code.strip().upper()
    print(f"  Processing discount code: '{code_upper}'")

    # Look up the discount code
    if code_upper not in DISCOUNT_CODES_DB:
        raise DiscountError(f"Discount code '{code_upper}' not found.")

    dc = DISCOUNT_CODES_DB[code_upper]

    # Check if active
    if not dc.is_active:
        raise DiscountError(f"Discount code '{code_upper}' is no longer active.")

    # Check max uses
    if dc.max_uses != -1 and dc.current_uses >= dc.max_uses:
        raise DiscountError(f"Discount code '{code_upper}' has reached its maximum number of uses.")

    # Check admin-only permission
    if dc.admin_only and not user.is_admin:
        raise DiscountError(
            f"Discount code '{code_upper}' is restricted to admin users only. "
            f"User '{user.name}' (tier: {user.tier.value}) does not have permission."
        )

    # Check tier permission
    if user.tier not in dc.allowed_tiers:
        allowed_tier_names = [t.value for t in dc.allowed_tiers]
        raise DiscountError(
            f"Discount code '{code_upper}' is not available for tier '{user.tier.value}'. "
            f"Allowed tiers: {', '.join(allowed_tier_names)}"
        )

    # Check minimum order amount
    if subtotal < dc.min_order_amount:
        raise DiscountError(
            f"Discount code '{code_upper}' requires a minimum order of ${dc.min_order_amount:.2f}. "
            f"Current subtotal: ${subtotal:.2f}"
        )

    # Calculate discount
    if dc.percentage > 0:
        discount_amount = round(subtotal * (dc.percentage / 100.0), 2)
        print(f"  Applying {dc.percentage}% discount: -${discount_amount:.2f}")

    if dc.flat_amount > 0:
        discount_amount += dc.flat_amount
        discount_amount = round(discount_amount, 2)
        print(f"  Applying flat ${dc.flat_amount:.2f} discount")

    # Ensure discount doesn't exceed subtotal
    if discount_amount > subtotal:
        discount_amount = subtotal
        print(f"  Discount capped at subtotal: ${discount_amount:.2f}")

    subtotal_after_discount = round(subtotal - discount_amount, 2)

    discount_info = {
        "code": code_upper,
        "percentage": dc.percentage,
        "flat_amount": dc.flat_amount,
        "total_discount": discount_amount
    }

    print(f"\n  ✓ Discount applied successfully!")
    print(f"  Original subtotal: ${subtotal:.2f}")
    print(f"  Discount: -${discount_amount:.2f}")
    print(f"  Subtotal after discount: ${subtotal_after_discount:.2f}")

    return {
        **cart_summary,
        "discount_amount": discount_amount,
        "discount_code_used": code_upper,
        "subtotal_after_discount": subtotal_after_discount,
        "discount_info": discount_info
    }


def step3_calculate_tax(
    discounted_summary: dict,
    tax_config: TaxConfig
) -> dict:
    """
    Step 3: Calculate tax based on location and product types.
    Returns updated summary with tax information.
    """
    print(f"\n{'='*60}")
    print(f"STEP 3: Calculating tax ({tax_config.state}, {tax_config.tax_rate}%)")
    print(f"{'='*60}")

    if tax_config.tax_rate < 0 or tax_config.tax_rate > 100:
        raise TaxCalculationError(
            f"Invalid tax rate: {tax_config.tax_rate}%. Must be between 0 and 100."
        )

    subtotal_after_discount = discounted_summary["subtotal_after_discount"]
    validated_items = discounted_summary["validated_items"]

    taxable_amount = 0.0
    exempt_amount = 0.0

    for item in validated_items:
        if item["product_id"] in tax_config.tax_exempt_products:
            exempt_amount += item["item_total"]
            print(f"  ○ {item['name']}: TAX EXEMPT (${item['item_total']:.2f})")
        else:
            taxable_amount += item["item_total"]
            print(f"  ● {item['name']}: Taxable (${item['item_total']:.2f})")

    # If a discount was applied, proportionally reduce taxable and exempt amounts
    original_subtotal = discounted_summary["subtotal"]
    if original_subtotal > 0 and discounted_summary["discount_amount"] > 0:
        discount_ratio = subtotal_after_discount / original_subtotal
        taxable_amount = round(taxable_amount * discount_ratio, 2)
        exempt_amount = round(exempt_amount * discount_ratio, 2)

    tax_amount = round(taxable_amount * (tax_config.tax_rate / 100.0), 2)
    total = round(subtotal_after_discount + tax_amount, 2)

    tax_info = {
        "state": tax_config.state,
        "tax_rate": tax_config.tax_rate,
        "taxable_amount": taxable_amount,
        "exempt_amount": exempt_amount,
        "tax_amount": tax_amount
    }

    print(f"\n  Taxable amount: ${taxable_amount:.2f}")
    print(f"  Exempt amount: ${exempt_amount:.2f}")
    print(f"  Tax ({tax_config.tax_rate}%): ${tax_amount:.2f}")
    print(f"  ✓ Total (with tax): ${total:.2f}")

    return {
        **discounted_summary,
        "tax_info": tax_info,
        "tax_amount": tax_amount,
        "total": total
    }


def step4_process_payment(
    taxed_summary: dict,
    payment_info: PaymentInfo
) -> dict:
    """
    Step 4: Process payment.
    Validates payment information and simulates payment processing.
    Returns updated summary with payment confirmation.
    """
    print(f"\n{'='*60}")
    print(f"STEP 4: Processing payment ({payment_info.method.value})")
    print(f"{'='*60}")

    total = taxed_summary["total"]
    user: User = taxed_summary["user"]

    if total <= 0:
        print(f"  Total is ${total:.2f}. No payment required.")
        transaction_id = f"FREE-{uuid.uuid4().hex[:8].upper()}"
        return {
            **taxed_summary,
            "payment_status": "success",
            "transaction_id": transaction_id,
            "payment_method": payment_info.method.value,
            "amount_charged": 0.0
        }

    # Validate payment method details
    if payment_info.method in (PaymentMethod.CREDIT_CARD, PaymentMethod.DEBIT_CARD):
        if not payment_info.card_number:
            raise PaymentError("Card number is required for card payments.")
        if not payment_info.expiry:
            raise PaymentError("Card expiry date is required.")
        if not payment_info.cvv:
            raise PaymentError("CVV is required for card payments.")

        # Basic card number validation (length check)
        cleaned_card = payment_info.card_number.replace(" ", "").replace("-", "")
        if not cleaned_card.isdigit() or len(cleaned_card) not in (13, 14, 15, 16):
            raise PaymentError("Invalid card number format.")

        if not payment_info.cvv.isdigit() or len(payment_info.cvv) not in (3, 4):
            raise PaymentError("Invalid CVV format.")

        masked_card = f"****-****-****-{cleaned_card[-4:]}"
        print(f"  Card: {masked_card}")

        # Simulate decline for specific test card
        if cleaned_card == "4000000000000002":
            raise PaymentError("Payment declined by card issuer. Please try another card.")

    elif payment_info.method == PaymentMethod.PAYPAL:
        if not payment_info.paypal_email:
            raise PaymentError("PayPal email is required for PayPal payments.")
        print(f"  PayPal account: {payment_info.paypal_email}")

    elif payment_info.method == PaymentMethod.BANK_TRANSFER:
        print(f"  Processing bank transfer...")

    # Simulate payment processing
    transaction_id = f"TXN-{uuid.uuid4().hex[:12].upper()}"
    print(f"  Processing ${total:.2f}...")
    print(f"  ✓ Payment successful!")
    print(f"  Transaction ID: {transaction_id}")

    # Log transaction
    transaction_record = {
        "transaction_id": transaction_id,
        "user_id": user.user_id,
        "amount": total,
        "method": payment_info.method.value,
        "status": "success",
        "timestamp": datetime.now().isoformat()
    }
    PAYMENT_TRANSACTIONS_DB.append(transaction_record)

    return {
        **taxed_summary,
        "payment_status": "success",
        "transaction_id": transaction_id,
        "payment_method": payment_info.method.value,
        "amount_charged": total
    }


def step5_create_order(payment_summary: dict) -> OrderRecord:
    """
    Step 5: Create order record.
    Creates and stores the final order record.
    """
    print(f"\n{'='*60}")
    print(f"STEP 5: Creating order record")
    print(f"{'='*60}")

    if payment_summary.get("payment_status") != "success":
        raise OrderCreationError("Cannot create order: Payment was not successful.")

    user: User = payment_summary["user"]
    order_id = f"ORD-{uuid.uuid4().hex[:10].upper()}"

    order = OrderRecord(
        order_id=order_id,
        user_id=user.user_id,
        items=payment_summary["validated_items"],
        subtotal=payment_summary["subtotal"],
        discount_applied=payment_summary["discount_amount"],
        tax_amount=payment_summary["tax_amount"],
        total=payment_summary["total"],
        discount_code_used=payment_summary.get("discount_code_used"),
        payment_method=payment_summary["payment_method"],
        status=OrderStatus.COMPLETED,
        created_at=datetime.now().isoformat(),
        transaction_id=payment_summary["transaction_id"]
    )

    # Store in "database"
    ORDERS_DB[order_id] = order

    # If a discount code was used, increment its usage count
    if order.discount_code_used and order.discount_code_used in DISCOUNT_CODES_DB:
        DISCOUNT_CODES_DB[order.discount_code_used].current_uses += 1

    print(f"  ✓ Order created successfully!")
    print(f"  Order ID: {order.order_id}")
    print(f"  User: {user.name} ({user.email})")
    print(f"  Items: {len(order.items)}")
    print(f"  Subtotal: ${order.subtotal:.2f}")
    print(f"  Discount: -${order.discount_applied:.2f}")
    print(f"  Tax: ${order.tax_amount:.2f}")
    print(f"  Total: ${order.total:.2f}")
    print(f"  Payment: {order.payment_method} (TXN: {order.transaction_id})")
    print(f"  Status: {order.status.value}")

    return order


def checkout(
    user: User,
    cart_items: list[CartItem],
    discount_code: Optional[str],
    tax_config: TaxConfig,
    payment_info: PaymentInfo
) -> OrderRecord:
    """
    Main multi-step checkout process.
    Orchestrates all 5 steps in sequence, where each step depends on the previous.
    """
    print(f"\n{'#'*60}")
    print(f"# CHECKOUT PROCESS STARTED")
    print(f"# User: {user.name} | Tier: {user.tier.value}")
    print(f"{'#'*60}")

    try:
        # Step 1: Validate cart
        cart_summary = step1_validate_cart(cart_items, user)

        # Step 2: Apply discount (depends on step 1 output)
        discounted_summary = step2_apply_discount(cart_summary, discount_code)

        # Step 3: Calculate tax (depends on step 2 output)
        taxed_summary = step3_calculate_tax(discounted_summary, tax_config)

        # Step 4: Process payment (depends on step 3 output)
        payment_summary = step4_process_payment(taxed_summary, payment_info)

        # Step 5: Create order record (depends on step 4 output)
        order = step5_create_order(payment_summary)

        print(f"\n{'#'*60}")
        print(f"# CHECKOUT COMPLETED SUCCESSFULLY")
        print(f"# Order: {order.order_id} | Total: ${order.total:.2f}")
        print(f"{'#'*60}\n")

        return order

    except CheckoutError as e:
        print(f"\n{'!'*60}")
        print(f"! CHECKOUT FAILED at step: {e.step}")
        print(f"! Error: {e.message}")
        print(f"{'!'*60}\n")
        raise


